        with open(filepath, 'rb') as f:
            data = f.read()
        
        if len(data) < 56:
            print(f"{filepath}: Too short to be a valid GFF (size: {len(data)} bytes)")
            return False
            
        sig = data[0:4]
        ver = data[4:8]
        
        print(f"File: {filepath}")
