        print(f"  Fields: offset {field_offset}, count {field_count}")
        print(f"  Labels: offset {label_offset}, count {label_count}")
        print(f"  Data: offset {data_offset}, count {data_count}")
        print(f"  Field Indices: offset {field_indices_offset}, count {field_indices_count}")
        print(f"  List Indices: offset {list_indices_offset}, count {list_indices_count}")
        
        # Check if offsets and sizes match file size
        expected_size = max(
            struct_offset + struct_count * 12,
            field_offset + field_count * 12,
            label_offset + label_count * 16,
            data_offset + data_count,
            field_indices_offset + field_indices_count,
            list_indices_offset + list_indices_count
        )
        print(f"  Actual file size: {len(data)} bytes")
        print(f"  Expected min size based on offsets: {expected_size} bytes")
        
